+    #[test]
+    fn ws_url_debug_clone_eq() {
+        let u = WsUrl {
+            host: "example.com".into(),
+            port: 80,
+            path: "/chat".into(),
+            tls: false,
+        };
+        let dbg = format!("{:?}", u);
+        assert!(dbg.contains("WsUrl"));
+        assert!(dbg.contains("example.com"));
+
+        let u2 = u.clone();
+        assert_eq!(u, u2);
+
+        let u3 = WsUrl {
+            host: "other.com".into(),
+            port: 443,
+            path: "/".into(),
+            tls: true,
+        };
+        assert_ne!(u, u3);
+    }
